  /* udx user if orgsegmentid or suborgsegmentid matches Custom_VSNT_Joiner_Details*/
  public boolean isUDXUser(){
    List orgSegmentIdList = joinerDetails.getList("orgSegmentId");
    List subOrgSegmentIdList = joinerDetails.getList("subOrgSegmentId");

    if(Util.nullSafeContains(orgSegmentIdList,managerOrgSegmentID) || Util.nullSafeContains(subOrgSegmentIdList, mgrSubOrgSegId))
    {
      return true;
    }
    return false;
  }

